{
  "mode": "method",
  "tests": [
    {
      "name": "valid_signup",
      "input": {
        "name": "John Doe",
        "email": "john@example.com",
        "password": "securePassword123"
      },
      "output": {
        "success": true,
        "message": "Signup successful"
      },
      "notes": "Tests a valid signup scenario."
    },
    {
      "name": "valid_login",
      "input": {
        "email": "john@example.com",
        "password": "securePassword123"
      },
      "output": {
        "success": true,
        "message": "Login successful"
      },
      "notes": "Tests a valid login scenario."
    },
    {
      "name": "signup_with_existing_email",
      "input": {
        "name": "Jane Doe",
        "email": "john@example.com",
        "password": "anotherPassword456"
      },
      "output": {
        "success": false,
        "message": "Email already in use"
      },
      "notes": "Tests signup with an email that is already registered."
    },
    {
      "name": "login_with_incorrect_password",
      "input": {
        "email": "john@example.com",
        "password": "wrongPassword"
      },
      "output": {
        "success": false,
        "message": "Invalid credentials"
      },
      "notes": "Tests login with an incorrect password."
    },
    {
      "name": "profile_display",
      "input": {
        "email": "john@example.com"
      },
      "output": {
        "name": "John Doe",
        "biography": "Software Developer",
        "country": "USA",
        "interests": ["ReactJS", "JavaScript"],
        "photo": "placeholder.jpg"
      },
      "notes": "Tests if the profile displays correct user details."
    },
    {
      "name": "signup_with_missing_fields",
      "input": {
        "name": "",
        "email": "missing@example.com",
        "password": ""
      },
      "output": {
        "success": false,
        "message": "Name and password are required"
      },
      "notes": "Tests signup with missing required fields."
    },
    {
      "name": "login_with_nonexistent_email",
      "input": {
        "email": "nonexistent@example.com",
        "password": "somePassword"
      },
      "output": {
        "success": false,
        "message": "Email not found"
      },
      "notes": "Tests login with an email that does not exist."
    },
    {
      "name": "profile_with_no_interests",
      "input": {
        "email": "john@example.com"
      },
      "output": {
        "name": "John Doe",
        "biography": "Software Developer",
        "country": "USA",
        "interests": [],
        "photo": "placeholder.jpg"
      },
      "notes": "Tests profile display when user has no interests."
    }
  ],
  "assumptions": "Email must be unique for each user. Password must meet security criteria.",
  "notes": "Ensure to handle both frontend and backend validations."
}
